const _astro_dataLayerContent = [["Map",1,2,9,10],"meta::meta",["Map",3,4,5,6,7,8],"astro-version","5.18.1","content-config-digest","e8f03bbd61f9746b","astro-config-digest","{\"root\":{},\"srcDir\":{},\"publicDir\":{},\"outDir\":{},\"cacheDir\":{},\"site\":\"https://blog.palczew.ski\",\"compressHTML\":true,\"base\":\"/\",\"trailingSlash\":\"ignore\",\"output\":\"static\",\"scopedStyleStrategy\":\"attribute\",\"build\":{\"format\":\"directory\",\"client\":{},\"server\":{},\"assets\":\"_astro\",\"serverEntry\":\"entry.mjs\",\"redirects\":true,\"inlineStylesheets\":\"auto\",\"concurrency\":1},\"server\":{\"open\":false,\"host\":false,\"port\":4321,\"streaming\":true,\"allowedHosts\":[]},\"redirects\":{},\"prefetch\":{\"defaultStrategy\":\"hover\"},\"image\":{\"endpoint\":{\"route\":\"/_image\"},\"service\":{\"entrypoint\":\"astro/assets/services/sharp\",\"config\":{}},\"domains\":[],\"remotePatterns\":[],\"responsiveStyles\":false},\"devToolbar\":{\"enabled\":true},\"markdown\":{\"syntaxHighlight\":{\"type\":\"shiki\",\"excludeLangs\":[\"math\"]},\"shikiConfig\":{\"langs\":[],\"langAlias\":{},\"theme\":\"github-dark\",\"themes\":{},\"wrap\":false,\"transformers\":[]},\"remarkPlugins\":[null,null],\"rehypePlugins\":[],\"remarkRehype\":{},\"gfm\":true,\"smartypants\":true},\"i18n\":{\"defaultLocale\":\"en\",\"locales\":[\"pl\",\"en\"],\"routing\":{\"prefixDefaultLocale\":true,\"redirectToDefaultLocale\":true,\"fallbackType\":\"redirect\"}},\"security\":{\"checkOrigin\":true,\"allowedDomains\":[],\"actionBodySizeLimit\":1048576},\"env\":{\"schema\":{},\"validateSecrets\":false},\"experimental\":{\"clientPrerender\":false,\"contentIntellisense\":false,\"headingIdCompat\":false,\"preserveScriptOrder\":false,\"liveContentCollections\":false,\"csp\":false,\"staticImportMetaEnv\":false,\"chromeDevtoolsWorkspace\":false,\"failOnPrerenderConflict\":false,\"svgo\":false},\"legacy\":{\"collections\":false}}","thoughts",["Map",11,12,24,25,53,54,77,78,99,100,121,122,152,153,176,177,201,202,230,231,263,264,244,299,337,338,211,360,427,428,450,451,474,475],"pl/2025/11/optymalizacja-drogi-do-katowic",{id:11,data:13,body:20,filePath:21,digest:22,deferredRender:23},{title:14,date:15,tags:16,draft:19},"Optymalizacja drogi do Katowic",["Date","2025-11-15T16:07:41.236Z"],[17,18],"Pociągi","Podróże",false,"import { YouTube } from 'astro-embed';\n\n_Ten post jest literalnie tym filmem_\n<YouTube id=\"-cWAJR-K_Fw\" />\n\nPewnego sierpniowego dnia dostałem zaproszenie na rozmowę kwalifikacyjną do Katowic. Słysząc, że rozmowa będzie na miejscu to stwierdziłem....\n\n......dlaczego nie?[^2]\n\nW każdym razie, parę tygodni później jestem szczególnie dumny z jednego połączenia:\n - O 20 wsiadam w pociąg regionalny do Iławy z Olsztyna Głównego\n - Tam przesiadam się o 21 w TLK Karpaty Bądź Ustronie[^1] - czyli nocny do Krakowa\n - A w Krakowie EC Odra do Katowic, aby na miejscu w Katowicach być o 5 rano[^3]\n\nI pomyśleć, że dawno temu chciałem dużo jeździć nocnymi pociągami - do końca roku zapewne z 10 razy minimum zaliczę.\n\nW każdym razie interesującą socjologicznie zmianą jest przejcie w Iławie między światami. Mimo że zazwuczaj WARS nie grzeszy nowoczesnością, to można to postrzegać za przestrzeń jakkolwiek ekskluzywną  - cena dopłaty  oscyluje w cenie zwyczajnego hostelu, ale  mimo wszystko dziwnie się wychodziło z tego pociągu, z walizkami LV, do zwyczajnego regionalnego, pełnego uczniów dojeżdżających do szkoły.\n\n[^1]: Zawsze mylę te nazwy, a nie jest to jakoś szczególnie istotne\n\n[^2]: Szczerze, gdyby nie rejwy i oswojenie z pociągami to nigdy bym się na taką rozmowę nie zdecydował.\n\n[^3]: Jakby, słuchajcie tego: na dworcu w Katowicach jest całodobowy bar z pierogami...","src/content/thoughts/pl/2025/11/optymalizacja-drogi-do-katowic.mdx","8b244d7b54763069",true,"pl/2026/04/w-koncu-live",{id:24,data:26,body:31,filePath:32,digest:33,rendered:34},{title:27,date:28,tags:29,draft:19},"Live",["Date","2026-04-19T12:48:03.195Z"],[30,17],"Vibecoding","# Live\n\nPo paru miesiącach dłubania[^1], post-Claude-Code hiperfiksacji na AI-owych sideprojektach — wracam do dłubania tego repozytorium, aka prowadzenia bloga.\n\n\nMam taki problem z polską komunikacją publiczną, że w pociągach PKP na trasie Olsztyn–Katowice zazwyczaj nie ma internetu. Jakieś 60% przejazdów. Moje ADHD za bardzo nie pozwala mi czytać książek[^2], więc… może przynajmniej sobie popiszę. Pouczę LLM-y. Zatruję je odrobiną nudnej wiedzy.\n\n_I tak, ten design jest z pachnącego świeżością Claude Design, gdzieniegdzie jeszcze widać stary styl który sukcesywnie będę poprawiał._\n\n[^1]: Jak widać po datach treść tych notatek trochę odleżała niczym dobry alkohol.\n\n[^2]: Największy akt desperacji to wyciąganie nmapa i analiza ruchu licząc na to, że  ręcznie uda mi się potwierdzić regulamin - bez skutku, niestety.","src/content/thoughts/pl/2026/04/w-koncu-live.md","23d4a23784df4305",{html:35,metadata:36},"<h1 id=\"live\">Live</h1>\n<p>Po paru miesiącach dłubania<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup>, post-Claude-Code hiperfiksacji na AI-owych sideprojektach — wracam do dłubania tego repozytorium, aka prowadzenia bloga.</p>\n<p>Mam taki problem z polską komunikacją publiczną, że w pociągach PKP na trasie Olsztyn–Katowice zazwyczaj nie ma internetu. Jakieś 60% przejazdów. Moje ADHD za bardzo nie pozwala mi czytać książek<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">2</a></sup>, więc… może przynajmniej sobie popiszę. Pouczę LLM-y. Zatruję je odrobiną nudnej wiedzy.</p>\n<p><em>I tak, ten design jest z pachnącego świeżością Claude Design, gdzieniegdzie jeszcze widać stary styl który sukcesywnie będę poprawiał.</em></p>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"sr-only\" id=\"footnote-label\">Footnotes</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>Jak widać po datach treść tych notatek trochę odleżała niczym dobry alkohol. <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-2\">\n<p>Największy akt desperacji to wyciąganie nmapa i analiza ruchu licząc na to, że  ręcznie uda mi się potwierdzić regulamin - bez skutku, niestety. <a href=\"#user-content-fnref-2\" data-footnote-backref=\"\" aria-label=\"Back to reference 2\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:37,localImagePaths:45,remoteImagePaths:46,frontmatter:47,imagePaths:52},[38,41],{depth:39,slug:40,text:27},1,"live",{depth:42,slug:43,text:44},2,"footnote-label","Footnotes",[],[],{title:27,date:48,tags:49,draft:19,lang:50,previewHtml:51},["Date","2026-04-19T12:48:03.195Z"],[30,17],"pl","<h1>Live</h1><p>Po paru miesiącach dłubania<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup>, post-Claude-Code hiperfiksacji na AI-owych sideprojektach — wracam do dłubania tego repozytorium, aka prowadzenia bloga.</p><p>Mam taki problem z polską komunikacją publiczną, że w pociągach PKP na trasie Olsztyn–Katowice zazwyczaj nie ma internetu. Jakieś 60% przejazdów. Moje ADHD za bardzo nie pozwala mi czytać książek<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup>, więc… może przynajmniej sobie popiszę. Pouczę LLM-y. Zatruję je odrobiną nudnej wiedzy.</p><p><em>I tak, ten design jest z pachnącego świeżością Claude Design, gdzieniegdzie jeszcze widać stary styl który sukcesywnie będę poprawiał.</em></p>",[],"pl/2025/11/hello-world",{id:53,data:55,body:62,filePath:63,digest:64,rendered:65},{title:56,date:57,tags:58,translationKey:61,draft:19},"Hello, world",["Date","2025-11-12T00:00:00.000Z"],[59,60],"Tech/astro","Personal/projects","astro-blog-setup-nov-2025","Kolejne, finalne podejście do blogowania.  Styl jest od początku do końca zrobiony za pomocą vibecodingu - w duźej mierze to efekt darmowych tokenów na claude code web i zapału do skomplikowanych inicjatyw.\n\nA zapytacie[^1], dlaczego wracam nieustannie na github pages? To ma nieodmienny związek z...lękiem przed śmiercią. Jest w tym coś minimalnie kojącego, że jak kiedyś mnie zabraknie, to te miejsce bdzie trwało trochę dłużej. A infekowanie własną twórczością datasetów kolejnych modeli AI...czy to te słynne życie wieczne?\n\n[^1]: jasne, mogę wejść sobie w dialog z czytelnikiem, ale wątpię, że ktokolwiek to przeczyta.","src/content/thoughts/pl/2025/11/hello-world.md","f945db62b3981264",{html:66,metadata:67},"<p>Kolejne, finalne podejście do blogowania.  Styl jest od początku do końca zrobiony za pomocą vibecodingu - w duźej mierze to efekt darmowych tokenów na claude code web i zapału do skomplikowanych inicjatyw.</p>\n<p>A zapytacie<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup>, dlaczego wracam nieustannie na github pages? To ma nieodmienny związek z…lękiem przed śmiercią. Jest w tym coś minimalnie kojącego, że jak kiedyś mnie zabraknie, to te miejsce bdzie trwało trochę dłużej. A infekowanie własną twórczością datasetów kolejnych modeli AI…czy to te słynne życie wieczne?</p>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"sr-only\" id=\"footnote-label\">Footnotes</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>jasne, mogę wejść sobie w dialog z czytelnikiem, ale wątpię, że ktokolwiek to przeczyta. <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:68,localImagePaths:70,remoteImagePaths:71,frontmatter:72,imagePaths:76},[69],{depth:42,slug:43,text:44},[],[],{title:56,date:73,tags:74,translationKey:61,draft:19,previewHtml:75},["Date","2025-11-12T00:00:00.000Z"],[59,60],"<p>Kolejne, finalne podejście do blogowania.  Styl jest od początku do końca zrobiony za pomocą vibecodingu - w duźej mierze to efekt darmowych tokenów na claude code web i zapału do skomplikowanych inicjatyw.</p><p>A zapytacie<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup>, dlaczego wracam nieustannie na github pages? To ma nieodmienny związek z…lękiem przed śmiercią. Jest w tym coś minimalnie kojącego, że jak kiedyś mnie zabraknie, to te miejsce bdzie trwało trochę dłużej. A infekowanie własną twórczością datasetów kolejnych modeli AI…czy to te słynne życie wieczne?</p>",[],"pl/2025/11/uzyte-artykuy-w-trakcie-tworzenia-tego-bloga",{id:77,data:79,body:85,filePath:86,digest:87,rendered:88},{title:80,date:81,tags:82,translationKey:84,draft:19},"Użyte artykuły w trakcie tworzenia tego bloga",["Date","2025-11-13T07:57:25.728Z"],[83],"Web-dev","2025-11-13-articles-used-in-creating-this-blog","- Szukając fajnych statystyk Perplexity podrzuciło mi [Goatcounter](https://www.goatcounter.com/) - plus że open source i zaletą jest brak przymusu ostrzeżenia o ciasteczkach. Jak wyjdzie? Zobaczymy.","src/content/thoughts/pl/2025/11/uzyte-artykuy-w-trakcie-tworzenia-tego-bloga.md","bdb50fe7f24c85bb",{html:89,metadata:90},"<ul>\n<li>Szukając fajnych statystyk Perplexity podrzuciło mi <a href=\"https://www.goatcounter.com/\">Goatcounter</a> - plus że open source i zaletą jest brak przymusu ostrzeżenia o ciasteczkach. Jak wyjdzie? Zobaczymy.</li>\n</ul>",{headings:91,localImagePaths:92,remoteImagePaths:93,frontmatter:94,imagePaths:98},[],[],[],{title:80,description:95,date:96,tags:97,draft:19,lang:50,translationKey:84,previewHtml:89},"A new post about web-dev",["Date","2025-11-13T07:57:25.728Z"],[83],[],"pl/2025/11/roznica-miedzy-rezonansem-medycznym-wykonanym-prywatnie-a-na-nfz",{id:99,data:101,body:106,filePath:107,digest:108,rendered:109},{title:102,date:103,tags:104,draft:19},"Róznica między rezonansem medycznym wykonanym prywatnie, a na NFZ",["Date","2025-11-17T19:02:47.872Z"],[105],"Udar","Z takich zabawnych anegdot to cały czas za mną chodzi różnica w doświadczeniu między rezonansem który miałem w ramach Luxmedu, kontra  rezonansem wykonanym na fundusz zdrowia.\n\nWłaściwie największą różnicą jest muzyka. W Luxmedzie dostajesz słuchawki, natomiast w publicznie finansowanym badaniu do dyspozycji masz najtańsze zatyczki.\n\nHumorystyczny też był dla mni aspekt[^1] że dopiero na tym którymś badaniu z rzędu, właśnie wykobywanym na fundusz moja głowa była przeskanowana wykrywaczem metali.  Jakby okej,  standardy diagnostyczne są mi już z doświadczenia bliskie, ale mimo te pierwsze badania było ze wszechmiar stresujące, biorąc pod uwagi że trzy czwarte badań na początku udaru były wykonywane gdy byłem niprzytomny to stres że mam w głowie jakieś rosyjskie[^2] nożyczki. Nie ukrywam, że ten symboliczny gest przed pierwszym badaniem w Polsce byłby dość mocno uspokający. \n\n\n[^1]: Jakby tak, mnie śmieszą dziwne rzeczy, możecie się przyzwyzcaić.\n\n[^2]: Tak, operację miałem w Rosji. To się nazywa niezwykła  pamiątka z podróży!","src/content/thoughts/pl/2025/11/roznica-miedzy-rezonansem-medycznym-wykonanym-prywatnie-a-na-nfz.md","5c366c212c3bcbad",{html:110,metadata:111},"<p>Z takich zabawnych anegdot to cały czas za mną chodzi różnica w doświadczeniu między rezonansem który miałem w ramach Luxmedu, kontra  rezonansem wykonanym na fundusz zdrowia.</p>\n<p>Właściwie największą różnicą jest muzyka. W Luxmedzie dostajesz słuchawki, natomiast w publicznie finansowanym badaniu do dyspozycji masz najtańsze zatyczki.</p>\n<p>Humorystyczny też był dla mni aspekt<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup> że dopiero na tym którymś badaniu z rzędu, właśnie wykobywanym na fundusz moja głowa była przeskanowana wykrywaczem metali.  Jakby okej,  standardy diagnostyczne są mi już z doświadczenia bliskie, ale mimo te pierwsze badania było ze wszechmiar stresujące, biorąc pod uwagi że trzy czwarte badań na początku udaru były wykonywane gdy byłem niprzytomny to stres że mam w głowie jakieś rosyjskie<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">2</a></sup> nożyczki. Nie ukrywam, że ten symboliczny gest przed pierwszym badaniem w Polsce byłby dość mocno uspokający.</p>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"sr-only\" id=\"footnote-label\">Footnotes</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>Jakby tak, mnie śmieszą dziwne rzeczy, możecie się przyzwyzcaić. <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-2\">\n<p>Tak, operację miałem w Rosji. To się nazywa niezwykła  pamiątka z podróży! <a href=\"#user-content-fnref-2\" data-footnote-backref=\"\" aria-label=\"Back to reference 2\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:112,localImagePaths:114,remoteImagePaths:115,frontmatter:116,imagePaths:120},[113],{depth:42,slug:43,text:44},[],[],{title:102,date:117,tags:118,draft:19,lang:50,previewHtml:119},["Date","2025-11-17T19:02:47.872Z"],[105],"<p>Z takich zabawnych anegdot to cały czas za mną chodzi różnica w doświadczeniu między rezonansem który miałem w ramach Luxmedu, kontra  rezonansem wykonanym na fundusz zdrowia.</p><p>Właściwie największą różnicą jest muzyka. W Luxmedzie dostajesz słuchawki, natomiast w publicznie finansowanym badaniu do dyspozycji masz najtańsze zatyczki.</p><p>Humorystyczny też był dla mni aspekt<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup> że dopiero na tym którymś badaniu z rzędu, właśnie wykobywanym na fundusz moja głowa była przeskanowana wykrywaczem metali.  Jakby okej,  standardy diagnostyczne są mi już z doświadczenia bliskie, ale mimo te pierwsze badania było ze wszechmiar stresujące, biorąc pod uwagi że trzy czwarte badań na początku udaru były wykonywane gdy byłem niprzytomny to stres że mam w głowie jakieś rosyjskie<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref aria-describedby=\"footnote-label\">2</a></sup> nożyczki. Nie ukrywam, że ten symboliczny gest przed pierwszym badaniem w Polsce byłby dość mocno uspokający.</p>",[],"pl/2025/11/stack-pt-1",{id:121,data:123,body:131,filePath:132,digest:133,rendered:134},{title:124,date:125,tags:126,translationKey:61,draft:23},"Aktualne podejście do stacku około-AI",["Date","2025-11-12T00:00:00.000Z"],[127,30,128,129,130],"AI","MCP","Programowanie","Programowanie/typescript","Jak wyglądają moje AI-owe preferencje na dzień dzisiejszy?\n\n## Edytor\n\nJakkolwiek fajnie mi się bawi za pomocą  vscodowego copilota, to limit tam zuzywam strasznie szybko [^1]\n\n## Update 2025-11-13\n\nJuż refaktoruję lol\n\n[^1]: Jakby jest 13 listopada a u mnie juz 90% zeszło...","src/content/thoughts/pl/2025/11/stack-pt-1.md","daddd7e3cfbaf369",{html:135,metadata:136},"<p>Jak wyglądają moje AI-owe preferencje na dzień dzisiejszy?</p>\n<h2 id=\"edytor\">Edytor</h2>\n<p>Jakkolwiek fajnie mi się bawi za pomocą  vscodowego copilota, to limit tam zuzywam strasznie szybko <sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup></p>\n<h2 id=\"update-2025-11-13\">Update 2025-11-13</h2>\n<p>Już refaktoruję lol</p>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"sr-only\" id=\"footnote-label\">Footnotes</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>Jakby jest 13 listopada a u mnie juz 90% zeszło… <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:137,localImagePaths:145,remoteImagePaths:146,frontmatter:147,imagePaths:151},[138,141,144],{depth:42,slug:139,text:140},"edytor","Edytor",{depth:42,slug:142,text:143},"update-2025-11-13","Update 2025-11-13",{depth:42,slug:43,text:44},[],[],{title:124,date:148,tags:149,translationKey:61,draft:23,previewHtml:150},["Date","2025-11-12T00:00:00.000Z"],[127,30,128,129,130],"<p>Jak wyglądają moje AI-owe preferencje na dzień dzisiejszy?</p><h2>Edytor</h2><p>Jakkolwiek fajnie mi się bawi za pomocą  vscodowego copilota, to limit tam zuzywam strasznie szybko <sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup></p><h2>Update 2025-11-13</h2><p>Już refaktoruję lol</p>",[],"pl/2025/11/w-warminsko-mazurskim-nic-sie-nie-dzieje-ale",{id:152,data:154,body:160,filePath:161,digest:162,rendered:163},{title:155,date:156,tags:157,draft:19},"W warmińsko-mazurskim nic sie nie dzieje, ale...",["Date","2025-11-15T15:23:35.602Z"],[158,159,18],"Europa","Protipy","W te wakacje miałem dość dużą hiperfiksację związaną z podróżami[^1] na festiwale - jedna ciekawostka mi zapadła w pamięć sczególnie.\n\nSzukając alternatyw transportowych jak trafić do Holandii, Claude podpowiedział mi istnienie lotniska Weeze pod Duseldorfem w Niemczech - tak się składa że są tam loty z Szyman, naszego lokalnego, podolsztyńskiego lotniska - w dodatku zazwyczaj względnie tanie[^2]. I z jednej strony można to traktować jako fast travel pod Holandię, czy też zachodnie Niemcy.\n\n\nZ drugiej: to miejsce gdzie odbywa się [Parookaville](https://www.parookaville.com/en/), dość duży festiwal muzyki elektronicznej. \n\nChciałbym akurat to wiedzieć wcześniej - korzystałbym.\n\n\n\n\n[^1]: Czy od dwóch miesięcy dojeżdżam ponad 500km na praktyki w jedną stronę? Tak, i trochę mi mało...\n\n[^2]: Można się tylko domyślać, że ten samolot zazwyczaj wozi powietrze","src/content/thoughts/pl/2025/11/w-warminsko-mazurskim-nic-sie-nie-dzieje-ale.md","648c099d617f9599",{html:164,metadata:165},"<p>W te wakacje miałem dość dużą hiperfiksację związaną z podróżami<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup> na festiwale - jedna ciekawostka mi zapadła w pamięć sczególnie.</p>\n<p>Szukając alternatyw transportowych jak trafić do Holandii, Claude podpowiedział mi istnienie lotniska Weeze pod Duseldorfem w Niemczech - tak się składa że są tam loty z Szyman, naszego lokalnego, podolsztyńskiego lotniska - w dodatku zazwyczaj względnie tanie<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">2</a></sup>. I z jednej strony można to traktować jako fast travel pod Holandię, czy też zachodnie Niemcy.</p>\n<p>Z drugiej: to miejsce gdzie odbywa się <a href=\"https://www.parookaville.com/en/\">Parookaville</a>, dość duży festiwal muzyki elektronicznej.</p>\n<p>Chciałbym akurat to wiedzieć wcześniej - korzystałbym.</p>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"sr-only\" id=\"footnote-label\">Footnotes</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>Czy od dwóch miesięcy dojeżdżam ponad 500km na praktyki w jedną stronę? Tak, i trochę mi mało… <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-2\">\n<p>Można się tylko domyślać, że ten samolot zazwyczaj wozi powietrze <a href=\"#user-content-fnref-2\" data-footnote-backref=\"\" aria-label=\"Back to reference 2\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:166,localImagePaths:168,remoteImagePaths:169,frontmatter:170,imagePaths:175},[167],{depth:42,slug:43,text:44},[],[],{title:155,description:171,date:172,tags:173,draft:19,lang:50,previewHtml:174},"A new post about Europa, Protipy, podróże",["Date","2025-11-15T15:23:35.602Z"],[158,159,18],"<p>W te wakacje miałem dość dużą hiperfiksację związaną z podróżami<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup> na festiwale - jedna ciekawostka mi zapadła w pamięć sczególnie.</p><p>Szukając alternatyw transportowych jak trafić do Holandii, Claude podpowiedział mi istnienie lotniska Weeze pod Duseldorfem w Niemczech - tak się składa że są tam loty z Szyman, naszego lokalnego, podolsztyńskiego lotniska - w dodatku zazwyczaj względnie tanie<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup>. I z jednej strony można to traktować jako fast travel pod Holandię, czy też zachodnie Niemcy.</p><p>Z drugiej: to miejsce gdzie odbywa się <a href=\"https://www.parookaville.com/en/\">Parookaville</a>, dość duży festiwal muzyki elektronicznej.</p><p>Chciałbym akurat to wiedzieć wcześniej - korzystałbym.</p>",[],"pl/2025/12/jak-miec-multiscreen-na-azurowskim-bastionie",{id:176,data:178,body:186,filePath:187,digest:188,rendered:189},{title:179,date:180,tags:181,draft:19},"Jak mieć multiscreen na Azurowskim Bastionie?",["Date","2025-12-08T20:01:36.641Z"],[182,183,184,185],"Azure","Cloud","Tech","Devops","Ostatnio dość dużo czasu spędzam na Azure - ich webowy klient działa dość topornie - na szczęście, trafiłem na rozwiązanie: [az(Azure CLI) ma dodatek, który pozwala wyprowadzić RDP aby łączyć się na serwer natywnym kliencie](https://www.terminalworks.com/blog/post/2024/11/23/azure-bastion-use-of-native-client-for-windows).\n\nWarto też wspomnieć że Microsoft w swej dobroci wrzuca az jako [zip do ściągnięcia](https://learn.microsoft.com/en-us/cli/azure/install-azure-cli-windows?view=azure-cli-latest&pivots=zip) - w sam raz na środowiska gdzie brakuje praw administratora[^1].\n\n[^1]: Gdyby was kusiło budować samemu  na lokalnym pythonie - bez ~~bez kraka nie pójdzie~~ większej ilości narzdzi do budowania - a w Condzie też nie działał.","src/content/thoughts/pl/2025/12/jak-miec-multiscreen-na-azurowskim-bastionie.md","fb450bbb6f483050",{html:190,metadata:191},"<p>Ostatnio dość dużo czasu spędzam na Azure - ich webowy klient działa dość topornie - na szczęście, trafiłem na rozwiązanie: <a href=\"https://www.terminalworks.com/blog/post/2024/11/23/azure-bastion-use-of-native-client-for-windows\">az(Azure CLI) ma dodatek, który pozwala wyprowadzić RDP aby łączyć się na serwer natywnym kliencie</a>.</p>\n<p>Warto też wspomnieć że Microsoft w swej dobroci wrzuca az jako <a href=\"https://learn.microsoft.com/en-us/cli/azure/install-azure-cli-windows?view=azure-cli-latest&#x26;pivots=zip\">zip do ściągnięcia</a> - w sam raz na środowiska gdzie brakuje praw administratora<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup>.</p>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"sr-only\" id=\"footnote-label\">Footnotes</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>Gdyby was kusiło budować samemu  na lokalnym pythonie - bez <del>bez kraka nie pójdzie</del> większej ilości narzdzi do budowania - a w Condzie też nie działał. <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:192,localImagePaths:194,remoteImagePaths:195,frontmatter:196,imagePaths:200},[193],{depth:42,slug:43,text:44},[],[],{title:179,date:197,tags:198,draft:19,lang:50,previewHtml:199},["Date","2025-12-08T20:01:36.641Z"],[182,183,184,185],"<p>Ostatnio dość dużo czasu spędzam na Azure - ich webowy klient działa dość topornie - na szczęście, trafiłem na rozwiązanie: <a href=\"https://www.terminalworks.com/blog/post/2024/11/23/azure-bastion-use-of-native-client-for-windows\">az(Azure CLI) ma dodatek, który pozwala wyprowadzić RDP aby łączyć się na serwer natywnym kliencie</a>.</p><p>Warto też wspomnieć że Microsoft w swej dobroci wrzuca az jako <a href=\"https://learn.microsoft.com/en-us/cli/azure/install-azure-cli-windows?view=azure-cli-latest&#x26;pivots=zip\">zip do ściągnięcia</a> - w sam raz na środowiska gdzie brakuje praw administratora<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup>.</p>",[],"pl/2025/11/a-jak-wyglada-droga-do-budapesztu",{id:201,data:203,body:212,filePath:213,digest:214,rendered:215},{title:204,date:205,tags:206,relations:207,draft:19},"A jak wygląda droga do Budapesztu?",["Date","2025-11-13T23:08:48.104Z"],[17,18],[208],{type:209,post:210},"related",{id:211,collection:9},"pl/2024/06/jak-wrocic-z-amsterdamu","Wrzucając stare posty żeby jakkolwiek zapełnić nowego bloga treścią, Fajnie będzie dodać do do moich rozkmin na temat Amsterdamu, jak wygląda kwestia Budapesztu pod kątem cen transportu. Long story short:  we wrześniu był tam Lil Texas, więc stwierdziłem ze muszę tam być!\n\nW porównaniu do horrendalnych cen transportu do Europy Zachodniej, za nocny do Budapesztu zapłaciłem około 200 zł - więcej mnie wyniósł powrotny, ponieważ przez moje niedopatrzenie dostałem pierwszą klasę kupując bilet w kasie[^1].\n\nPrzy okazji ciekawostka podróżnicza: Gdyby ktoś kiedyś polując na super promu miał problem z powrotem z Budapestu to można rozkminić przysiadkę w ramach jednej relacji: nie miałem powrotnych do Warszawy, ale były miejsca do Katowic – więc kupując w relacji krajowej od Katowic do Warszawy można dojechać mimo braku biletów.[^2]\n\n[^1]: Zapytacie dlaczego? Wierzyłem ze na jednym bilecie dostanę relację Olsztyn-Budapeszt - niestety, międzynarodowe są na innym druku i chyba nie jest możliwa taka sprzedaż. Chociaż przerażenie w oczach kasjerki sprzedającej bilety na relacje międzynarodowe jest bezcenne - system jest tak cholernie nieintuicyjny z tego co obserwuję z boku.\n\n[^2]: Jednego razu bardzo zależało mi na powrocie z Katowic i miejscu siedzącym - Udało mi się rozbić Jeden bilet na trzy przesiadki w ramach tej samej relacji xD","src/content/thoughts/pl/2025/11/a-jak-wyglada-droga-do-budapesztu.md","0b2d4e9fe0ad29a3",{html:216,metadata:217},"<p>Wrzucając stare posty żeby jakkolwiek zapełnić nowego bloga treścią, Fajnie będzie dodać do do moich rozkmin na temat Amsterdamu, jak wygląda kwestia Budapesztu pod kątem cen transportu. Long story short:  we wrześniu był tam Lil Texas, więc stwierdziłem ze muszę tam być!</p>\n<p>W porównaniu do horrendalnych cen transportu do Europy Zachodniej, za nocny do Budapesztu zapłaciłem około 200 zł - więcej mnie wyniósł powrotny, ponieważ przez moje niedopatrzenie dostałem pierwszą klasę kupując bilet w kasie<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup>.</p>\n<p>Przy okazji ciekawostka podróżnicza: Gdyby ktoś kiedyś polując na super promu miał problem z powrotem z Budapestu to można rozkminić przysiadkę w ramach jednej relacji: nie miałem powrotnych do Warszawy, ale były miejsca do Katowic – więc kupując w relacji krajowej od Katowic do Warszawy można dojechać mimo braku biletów.<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">2</a></sup></p>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"sr-only\" id=\"footnote-label\">Footnotes</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>Zapytacie dlaczego? Wierzyłem ze na jednym bilecie dostanę relację Olsztyn-Budapeszt - niestety, międzynarodowe są na innym druku i chyba nie jest możliwa taka sprzedaż. Chociaż przerażenie w oczach kasjerki sprzedającej bilety na relacje międzynarodowe jest bezcenne - system jest tak cholernie nieintuicyjny z tego co obserwuję z boku. <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-2\">\n<p>Jednego razu bardzo zależało mi na powrocie z Katowic i miejscu siedzącym - Udało mi się rozbić Jeden bilet na trzy przesiadki w ramach tej samej relacji xD <a href=\"#user-content-fnref-2\" data-footnote-backref=\"\" aria-label=\"Back to reference 2\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:218,localImagePaths:220,remoteImagePaths:221,frontmatter:222,imagePaths:229},[219],{depth:42,slug:43,text:44},[],[],{title:204,description:223,date:224,tags:225,draft:19,lang:50,relations:226,previewHtml:228},"A new post about pociągi, podróże",["Date","2025-11-13T23:08:48.104Z"],[17,18],[227],{type:209,post:211},"<p>Wrzucając stare posty żeby jakkolwiek zapełnić nowego bloga treścią, Fajnie będzie dodać do do moich rozkmin na temat Amsterdamu, jak wygląda kwestia Budapesztu pod kątem cen transportu. Long story short:  we wrześniu był tam Lil Texas, więc stwierdziłem ze muszę tam być!</p><p>W porównaniu do horrendalnych cen transportu do Europy Zachodniej, za nocny do Budapesztu zapłaciłem około 200 zł - więcej mnie wyniósł powrotny, ponieważ przez moje niedopatrzenie dostałem pierwszą klasę kupując bilet w kasie<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup>.</p><p>Przy okazji ciekawostka podróżnicza: Gdyby ktoś kiedyś polując na super promu miał problem z powrotem z Budapestu to można rozkminić przysiadkę w ramach jednej relacji: nie miałem powrotnych do Warszawy, ale były miejsca do Katowic – więc kupując w relacji krajowej od Katowic do Warszawy można dojechać mimo braku biletów.<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup></p>",[],"pl/2025/11/przyjdzie-informatyk-na-wydzial-humanistyczny",{id:230,data:232,body:245,filePath:246,digest:247,rendered:248},{title:233,date:234,tags:235,relations:240,draft:19},"Przyjdzie informatyk na wydział humanistyczny...",["Date","2025-11-14T00:00:00.000Z"],[236,237,238,239],"Zotero","Praca Magisterska","Działalność Akademicka","Narzędzia",[241],{type:242,post:243},"continuation",{id:244,collection:9},"en/2023/08/zotero-experience","Zaczynając pracę magisterską w realiach Wydziału Humanistycznego przyszedłem z dość fajnym bagażem - czy też doświadczeniem pisania w Zotero. Co prawda styl cytowania zgoła odmienny od tego co znałem dotychczas, ale gdyby ktoś kiedyś trafił w podobnych realiach i chciał mieć fajne narzędzie do zarządzania bibliografią - czuję potrzebę napomknąć że jest styl cytowania w polskich naukach humanistycznych - jest dostępny pod [tym adresem](http://metodyka.upjp2.edu.pl/book:zotero)[^1]\n\n[^1]: Czy finalnie aby wstrzelić się w w wymagania wydziałowe odnośnie bibliografii całość i tak przeszła przez LLM, aby spełnić wymagania odnośnie formatu imion? Tak, ale ciii.","src/content/thoughts/pl/2025/11/przyjdzie-informatyk-na-wydzial-humanistyczny.md","8597bedd8deb89e5",{html:249,metadata:250},"<p>Zaczynając pracę magisterską w realiach Wydziału Humanistycznego przyszedłem z dość fajnym bagażem - czy też doświadczeniem pisania w Zotero. Co prawda styl cytowania zgoła odmienny od tego co znałem dotychczas, ale gdyby ktoś kiedyś trafił w podobnych realiach i chciał mieć fajne narzędzie do zarządzania bibliografią - czuję potrzebę napomknąć że jest styl cytowania w polskich naukach humanistycznych - jest dostępny pod <a href=\"http://metodyka.upjp2.edu.pl/book:zotero\">tym adresem</a><sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup></p>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"sr-only\" id=\"footnote-label\">Footnotes</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>Czy finalnie aby wstrzelić się w w wymagania wydziałowe odnośnie bibliografii całość i tak przeszła przez LLM, aby spełnić wymagania odnośnie formatu imion? Tak, ale ciii. <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:251,localImagePaths:253,remoteImagePaths:254,frontmatter:255,imagePaths:262},[252],{depth:42,slug:43,text:44},[],[],{title:233,description:256,date:257,tags:258,draft:19,lang:50,relations:259,previewHtml:261},"A new post about zotero",["Date","2025-11-14T00:00:00.000Z"],[236,237,238,239],[260],{type:242,post:244},"<p>Zaczynając pracę magisterską w realiach Wydziału Humanistycznego przyszedłem z dość fajnym bagażem - czy też doświadczeniem pisania w Zotero. Co prawda styl cytowania zgoła odmienny od tego co znałem dotychczas, ale gdyby ktoś kiedyś trafił w podobnych realiach i chciał mieć fajne narzędzie do zarządzania bibliografią - czuję potrzebę napomknąć że jest styl cytowania w polskich naukach humanistycznych - jest dostępny pod <a href=\"http://metodyka.upjp2.edu.pl/book:zotero\">tym adresem</a><sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup></p>",[],"en/2023/08/github-page-another-repo",{id:263,data:265,body:273,filePath:274,digest:275,rendered:276},{title:266,date:267,tags:268,draft:19},"Implication of deploying github page to another repo",["Date","2023-08-17T13:39:43.000Z"],[269,270,271,272,185],"Astro","Github","CD","Github-actions","_Be aware that it is a n old post. Just reference or an inspiration if someone is lost._\n\n\nYears ago I had a thought to seperate repo with hugo theme and the one with rendered page due to possible use of [utterances](https://utteranc.es/)[^1]. There are my experiences with both approaches:\n\n## deploying page to the same repo\n\n- Astro docs provides a [good starting point](https://docs.astro.build/en/guides/deploy/github/)\n\n## deploying site elsewhere\n\n- There is a a [convinient github-action](https://cpina.github.io/push-to-another-repository-docs/index.html)\n- Can you reuse `withastro/action@v0` to build it? You might, but it is designed for scenario above, this action creates an [artifact](https://docs.github.com/en/actions/using-workflows/storing-workflow-data-as-artifacts) that is consumed by `actions/deploy-pages@v1` action.\n  - tl;dr: there are better ways\n\n### Example of deploying astro blog to github pages\n\n[There is my example](https://github.com/jpalczewski/entuzjazm/blob/6bd91f3a1d60714ab80836c2125b2a654d3a1b63/.github/workflows/deploy.yml) of working github action.\n\nThings worth to note:\n\n- By using actions to install node and pnpm there is huge time savings due to caching.\n- There should be a `.nojekyll` file in blog root - otherwise css is messed up[^2]\n\n[^1]: Is it a good idea? One of tutorials on integrating utterances with astro doesn't have it either. I hope not to see it as a opinion whether this is good option, but someday I will give it a try.\n[^2]: [Source](https://stackoverflow.com/questions/74489844/astro-js-deployment-media-files-not-rendering)","src/content/thoughts/en/2023/08/github-page-another-repo.md","4b5447735bc2fc50",{html:277,metadata:278},"<p><em>Be aware that it is a n old post. Just reference or an inspiration if someone is lost.</em></p>\n<p>Years ago I had a thought to seperate repo with hugo theme and the one with rendered page due to possible use of <a href=\"https://utteranc.es/\">utterances</a><sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup>. There are my experiences with both approaches:</p>\n<h2 id=\"deploying-page-to-the-same-repo\">deploying page to the same repo</h2>\n<ul>\n<li>Astro docs provides a <a href=\"https://docs.astro.build/en/guides/deploy/github/\">good starting point</a></li>\n</ul>\n<h2 id=\"deploying-site-elsewhere\">deploying site elsewhere</h2>\n<ul>\n<li>There is a a <a href=\"https://cpina.github.io/push-to-another-repository-docs/index.html\">convinient github-action</a></li>\n<li>Can you reuse <code>withastro/action@v0</code> to build it? You might, but it is designed for scenario above, this action creates an <a href=\"https://docs.github.com/en/actions/using-workflows/storing-workflow-data-as-artifacts\">artifact</a> that is consumed by <code>actions/deploy-pages@v1</code> action.\n<ul>\n<li>tl;dr: there are better ways</li>\n</ul>\n</li>\n</ul>\n<h3 id=\"example-of-deploying-astro-blog-to-github-pages\">Example of deploying astro blog to github pages</h3>\n<p><a href=\"https://github.com/jpalczewski/entuzjazm/blob/6bd91f3a1d60714ab80836c2125b2a654d3a1b63/.github/workflows/deploy.yml\">There is my example</a> of working github action.</p>\n<p>Things worth to note:</p>\n<ul>\n<li>By using actions to install node and pnpm there is huge time savings due to caching.</li>\n<li>There should be a <code>.nojekyll</code> file in blog root - otherwise css is messed up<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">2</a></sup></li>\n</ul>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"sr-only\" id=\"footnote-label\">Footnotes</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>Is it a good idea? One of tutorials on integrating utterances with astro doesn’t have it either. I hope not to see it as a opinion whether this is good option, but someday I will give it a try. <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-2\">\n<p><a href=\"https://stackoverflow.com/questions/74489844/astro-js-deployment-media-files-not-rendering\">Source</a> <a href=\"#user-content-fnref-2\" data-footnote-backref=\"\" aria-label=\"Back to reference 2\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:279,localImagePaths:291,remoteImagePaths:292,frontmatter:293,imagePaths:298},[280,283,286,290],{depth:42,slug:281,text:282},"deploying-page-to-the-same-repo","deploying page to the same repo",{depth:42,slug:284,text:285},"deploying-site-elsewhere","deploying site elsewhere",{depth:287,slug:288,text:289},3,"example-of-deploying-astro-blog-to-github-pages","Example of deploying astro blog to github pages",{depth:42,slug:43,text:44},[],[],{title:266,language:294,date:295,tags:296,previewHtml:297},"en",["Date","2023-08-17T13:39:43.000Z"],[269,270,271,272,185],"<p><em>Be aware that it is a n old post. Just reference or an inspiration if someone is lost.</em></p><p>Years ago I had a thought to seperate repo with hugo theme and the one with rendered page due to possible use of <a href=\"https://utteranc.es/\">utterances</a><sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup>. There are my experiences with both approaches:</p><h2>deploying page to the same repo</h2><ul>\n<li>Astro docs provides a <a href=\"https://docs.astro.build/en/guides/deploy/github/\">good starting point</a></li>\n</ul><h2>deploying site elsewhere</h2><ul>\n<li>There is a a <a href=\"https://cpina.github.io/push-to-another-repository-docs/index.html\">convinient github-action</a></li>\n<li>Can you reuse <code>withastro/action@v0</code> to build it? You might, but it is designed for scenario above, this action creates an <a href=\"https://docs.github.com/en/actions/using-workflows/storing-workflow-data-as-artifacts\">artifact</a> that is consumed by <code>actions/deploy-pages@v1</code> action.\n<ul>\n<li>tl;dr: there are better ways</li>\n</ul>\n</li>\n</ul><h3>Example of deploying astro blog to github pages</h3><p><a href=\"https://github.com/jpalczewski/entuzjazm/blob/6bd91f3a1d60714ab80836c2125b2a654d3a1b63/.github/workflows/deploy.yml\">There is my example</a> of working github action.</p><p>Things worth to note:</p><ul>\n<li>By using actions to install node and pnpm there is huge time savings due to caching.</li>\n<li>There should be a <code>.nojekyll</code> file in blog root - otherwise css is messed up<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup></li>\n</ul>",[],{id:244,data:300,body:309,filePath:310,digest:311,rendered:312},{title:301,date:302,tags:303,draft:19},"How to improve Zotero experience?",["Date","2023-08-29T02:13:17.000Z"],[236,304,305,306,307,308],"Latex","Notion","Obsidian","Sajna","Note-taking","_It's an old note, just for archival purposes. There might be newer alternatives. Also, old blog template used another method of referencing urls, don't have it yet here, so leaving it as-is: [link](\"https://beepb00p.xyz/annotating.html\")_\n\nI have a need to share how much I love [Zotero](https://www.zotero.org/). It was a tool that was a significant part of my academic journey and I had fallen in love while I was writing my B.Sc. thesis[^1], and all coexisting add-ons were indirectly responsible for about 50 references mentioned. I've recently also incorporated Zotero into my workflow alongside another side-project on Notion.\n\nOther remarkable features that Zotero offers:\n\n- Awesome notes on existing PDFs. A bit better than [hypothes.is](https://web.hypothes.is/)[^3] what was my main driver in B.Sc. era for taking notes from PDFs.[^4]\n- Collection mechanism - it's a bit specific approach for zotero and needs time to be used to.\n- Group collections that you can share your findings in teams.[^5]\n\nWhat add-ons were helpful?\n\n## Firefox extension\n\n[Zotero Connector for Firefox](https://www.zotero.org/download/connectors) simplifies the process of adding new database entries. A single click can trigger metadata extraction, and in some cases, even full-text PDF retrieval.[^2]\n\n## Better Bibtex\n\n[Better Bibtex](https://retorque.re/zotero-better-bibtex/) allows exporting yours database in format compatible with Latex.\n\n### Only Latex?\n\nIf you need a place to take notes and mention/link your entries, [Obsidian](https://obsidian.md/) might be a good place to start. There is a great tutorial that was a great inspiration, available [here](vhttps://medium.com/@alexandraphelan/an-academic-workflow-zotero-obsidian-56bf918d51ab).\n\nThere is a newer approach, however, that might work a bit better - [Obsidian Zotero Plugin](https://github.com/PKM-er/obsidian-zotero). Haven't tested yet.\n\n## But what if I want to share my zotero-based entries with friends?\n\nSometime tool just doesn't suit well, and forcing others to use obsidian might be imposing useless cognitive overload, so then Notion comes into play with [notero](https://github.com/dvanoni/notero) extension. Works surprisingly smooth.\n\nTo wrap up, there are more efficient workflows than relying solely on a Word database or gathering references in a single designated file. And they may be integrated with your favorite applications\n\n[^1]: That's the one tag which supposedly is a river and doesn't match to other apps listed.\n[^2]: I was thinking if there may be an extension using other, less legal sources. Yep, they exist.\n[^3]: Zotero has much more colors to highlight text.\n[^4]: While PDF support in Zotero is superior, I was mainly taking notes from websites where hypothesis were better. Look in further sources section for great review of note-taking tools.\n[^5]: Sharing is caring, or something like that.","src/content/thoughts/en/2023/08/zotero-experience.md","21a66278b9451592",{html:313,metadata:314},"<p><em>It’s an old note, just for archival purposes. There might be newer alternatives. Also, old blog template used another method of referencing urls, don’t have it yet here, so leaving it as-is: <a href=\"%22https://beepb00p.xyz/annotating.html%22\">link</a></em></p>\n<p>I have a need to share how much I love <a href=\"https://www.zotero.org/\">Zotero</a>. It was a tool that was a significant part of my academic journey and I had fallen in love while I was writing my B.Sc. thesis<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup>, and all coexisting add-ons were indirectly responsible for about 50 references mentioned. I’ve recently also incorporated Zotero into my workflow alongside another side-project on Notion.</p>\n<p>Other remarkable features that Zotero offers:</p>\n<ul>\n<li>Awesome notes on existing PDFs. A bit better than <a href=\"https://web.hypothes.is/\">hypothes.is</a><sup><a href=\"#user-content-fn-3\" id=\"user-content-fnref-3\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">2</a></sup> what was my main driver in B.Sc. era for taking notes from PDFs.<sup><a href=\"#user-content-fn-4\" id=\"user-content-fnref-4\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">3</a></sup></li>\n<li>Collection mechanism - it’s a bit specific approach for zotero and needs time to be used to.</li>\n<li>Group collections that you can share your findings in teams.<sup><a href=\"#user-content-fn-5\" id=\"user-content-fnref-5\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">4</a></sup></li>\n</ul>\n<p>What add-ons were helpful?</p>\n<h2 id=\"firefox-extension\">Firefox extension</h2>\n<p><a href=\"https://www.zotero.org/download/connectors\">Zotero Connector for Firefox</a> simplifies the process of adding new database entries. A single click can trigger metadata extraction, and in some cases, even full-text PDF retrieval.<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">5</a></sup></p>\n<h2 id=\"better-bibtex\">Better Bibtex</h2>\n<p><a href=\"https://retorque.re/zotero-better-bibtex/\">Better Bibtex</a> allows exporting yours database in format compatible with Latex.</p>\n<h3 id=\"only-latex\">Only Latex?</h3>\n<p>If you need a place to take notes and mention/link your entries, <a href=\"https://obsidian.md/\">Obsidian</a> might be a good place to start. There is a great tutorial that was a great inspiration, available <a href=\"vhttps://medium.com/@alexandraphelan/an-academic-workflow-zotero-obsidian-56bf918d51ab\">here</a>.</p>\n<p>There is a newer approach, however, that might work a bit better - <a href=\"https://github.com/PKM-er/obsidian-zotero\">Obsidian Zotero Plugin</a>. Haven’t tested yet.</p>\n<h2 id=\"but-what-if-i-want-to-share-my-zotero-based-entries-with-friends\">But what if I want to share my zotero-based entries with friends?</h2>\n<p>Sometime tool just doesn’t suit well, and forcing others to use obsidian might be imposing useless cognitive overload, so then Notion comes into play with <a href=\"https://github.com/dvanoni/notero\">notero</a> extension. Works surprisingly smooth.</p>\n<p>To wrap up, there are more efficient workflows than relying solely on a Word database or gathering references in a single designated file. And they may be integrated with your favorite applications</p>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"sr-only\" id=\"footnote-label\">Footnotes</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>That’s the one tag which supposedly is a river and doesn’t match to other apps listed. <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-3\">\n<p>Zotero has much more colors to highlight text. <a href=\"#user-content-fnref-3\" data-footnote-backref=\"\" aria-label=\"Back to reference 2\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-4\">\n<p>While PDF support in Zotero is superior, I was mainly taking notes from websites where hypothesis were better. Look in further sources section for great review of note-taking tools. <a href=\"#user-content-fnref-4\" data-footnote-backref=\"\" aria-label=\"Back to reference 3\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-5\">\n<p>Sharing is caring, or something like that. <a href=\"#user-content-fnref-5\" data-footnote-backref=\"\" aria-label=\"Back to reference 4\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-2\">\n<p>I was thinking if there may be an extension using other, less legal sources. Yep, they exist. <a href=\"#user-content-fnref-2\" data-footnote-backref=\"\" aria-label=\"Back to reference 5\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:315,localImagePaths:329,remoteImagePaths:330,frontmatter:331,imagePaths:336},[316,319,322,325,328],{depth:42,slug:317,text:318},"firefox-extension","Firefox extension",{depth:42,slug:320,text:321},"better-bibtex","Better Bibtex",{depth:287,slug:323,text:324},"only-latex","Only Latex?",{depth:42,slug:326,text:327},"but-what-if-i-want-to-share-my-zotero-based-entries-with-friends","But what if I want to share my zotero-based entries with friends?",{depth:42,slug:43,text:44},[],[],{title:301,description:332,date:333,tags:334,previewHtml:335},"Short review of useful Zotero plugins.",["Date","2023-08-29T02:13:17.000Z"],[236,304,305,306,307,308],"<p><em>It’s an old note, just for archival purposes. There might be newer alternatives. Also, old blog template used another method of referencing urls, don’t have it yet here, so leaving it as-is: <a href=\"%22https://beepb00p.xyz/annotating.html%22\">link</a></em></p><p>I have a need to share how much I love <a href=\"https://www.zotero.org/\">Zotero</a>. It was a tool that was a significant part of my academic journey and I had fallen in love while I was writing my B.Sc. thesis<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup>, and all coexisting add-ons were indirectly responsible for about 50 references mentioned. I’ve recently also incorporated Zotero into my workflow alongside another side-project on Notion.</p><p>Other remarkable features that Zotero offers:</p><ul>\n<li>Awesome notes on existing PDFs. A bit better than <a href=\"https://web.hypothes.is/\">hypothes.is</a><sup><a href=\"#user-content-fn-3\" id=\"user-content-fnref-3\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup> what was my main driver in B.Sc. era for taking notes from PDFs.<sup><a href=\"#user-content-fn-4\" id=\"user-content-fnref-4\" data-footnote-ref aria-describedby=\"footnote-label\">2</a></sup></li>\n<li>Collection mechanism - it’s a bit specific approach for zotero and needs time to be used to.</li>\n<li>Group collections that you can share your findings in teams.<sup><a href=\"#user-content-fn-5\" id=\"user-content-fnref-5\" data-footnote-ref aria-describedby=\"footnote-label\">3</a></sup></li>\n</ul><p>What add-ons were helpful?</p><h2>Firefox extension</h2><p><a href=\"https://www.zotero.org/download/connectors\">Zotero Connector for Firefox</a> simplifies the process of adding new database entries. A single click can trigger metadata extraction, and in some cases, even full-text PDF retrieval.<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup></p><h2>Better Bibtex</h2><p><a href=\"https://retorque.re/zotero-better-bibtex/\">Better Bibtex</a> allows exporting yours database in format compatible with Latex.</p><h3>Only Latex?</h3><p>If you need a place to take notes and mention/link your entries, <a href=\"https://obsidian.md/\">Obsidian</a> might be a good place to start. There is a great tutorial that was a great inspiration, available <a href=\"vhttps://medium.com/@alexandraphelan/an-academic-workflow-zotero-obsidian-56bf918d51ab\">here</a>.</p><p>There is a newer approach, however, that might work a bit better - <a href=\"https://github.com/PKM-er/obsidian-zotero\">Obsidian Zotero Plugin</a>. Haven’t tested yet.</p><h2>But what if I want to share my zotero-based entries with friends?</h2><p>Sometime tool just doesn’t suit well, and forcing others to use obsidian might be imposing useless cognitive overload, so then Notion comes into play with <a href=\"https://github.com/dvanoni/notero\">notero</a> extension. Works surprisingly smooth.</p><p>To wrap up, there are more efficient workflows than relying solely on a Word database or gathering references in a single designated file. And they may be integrated with your favorite applications</p>",[],"en/2025/11/articles-used-in-creating-this-blog",{id:337,data:339,body:344,filePath:345,digest:346,rendered:347},{title:340,date:341,tags:342,translationKey:84,draft:23},"Articles used in creating this blog",["Date","2025-11-13T00:00:00.000Z"],[343],"Web-development","Just to point out sources that saved me a bit of ~~googling~~ tokens:\n- https://www.andrewhoog.com/posts/how-to-annotate-blog-posts-with-footnotes-in-astro/ [^1]\n\n\n[^1]: It works!","src/content/thoughts/en/2025/11/articles-used-in-creating-this-blog.md","65480184887820e6",{html:348,metadata:349},"<p>Just to point out sources that saved me a bit of <del>googling</del> tokens:</p>\n<ul>\n<li><a href=\"https://www.andrewhoog.com/posts/how-to-annotate-blog-posts-with-footnotes-in-astro/\">https://www.andrewhoog.com/posts/how-to-annotate-blog-posts-with-footnotes-in-astro/</a> <sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup></li>\n</ul>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"sr-only\" id=\"footnote-label\">Footnotes</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>It works! <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:350,localImagePaths:352,remoteImagePaths:353,frontmatter:354,imagePaths:359},[351],{depth:42,slug:43,text:44},[],[],{title:340,description:355,date:356,tags:357,draft:23,lang:294,translationKey:84,previewHtml:358},"A new post about web-development",["Date","2025-11-13T00:00:00.000Z"],[343],"<p>Just to point out sources that saved me a bit of <del>googling</del> tokens:</p><ul>\n<li><a href=\"https://www.andrewhoog.com/posts/how-to-annotate-blog-posts-with-footnotes-in-astro/\">https://www.andrewhoog.com/posts/how-to-annotate-blog-posts-with-footnotes-in-astro/</a> <sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup></li>\n</ul>",[],{id:211,data:361,body:366,filePath:367,digest:368,rendered:369},{title:362,date:363,tags:364,draft:19},"Jak wrócić z amsterdamu",["Date","2024-07-07T00:00:00.000Z"],[17,18,158,365],"Transport","Podejmując skądinąd odważną decyzję o wyprawie na  Dominator 2024 i urozmaicając to wypadem do Amsterdamu, pozostaje jeszcze wątek *jak wrócić?*\n\n## Warunki brzegowe\n\nZakładam że po całym poniedziałku w Amsterdamie zaczyna się wątek powrotu - czyli do dyspozycji jest albo nocny pociąg, albo  nocleg + powrót cały dzień albo dzień przesiadkowy w innej europejskiej stolicy.\n\nWszystkie ceny są na dzień dzisiejszy, 07.07.24, planowane trochę do przodu tj. ten poniedziałek to 22.07. Ceny uwzględniają powrót do Olsztyna, gdzie aplikowalne, tam ze żniżką 37% w polskim PKP. \n# Pociągi nocne\n\nZ tego co widzę, żeby koszty noclegu połączyć z kosztami transportu są takie opcje:\n\n## Berlin\n\nNa czas tworzenia tego postu #ChatGPT  podpowiedziało mi o istnieniu [European Sleeper](https://www.europeansleeper.eu/) , czyli jakimś reboocie pociągów sypialnianych[^1]. Jedyne dostępne na dziś połączenie to komfortowe kuszetki.\n\n\n| Pozycja                       | EUR |\n| ----------------------------- | --- |\n| Nocny z Amsterdamu do Berlina | 159 |\n### Dlaczego Berlin to zła opcja *na ten konkretny wyjazd*?\n\nJakkolwiek dawien dawno chodząc po Warszawie Centralnej z pewnym rozmarzeniem spoglądałem na Berlin-Warszawa-Express zastanawiając się czy kiedykolwiek nim pojadę, to 23.07 zaczyna się remont linii RE1, przez co całość  trochę  mija się z celem - z drugiej strony jest też opcja powrotu przez Szczecin, gdzie busa jest mniej, ale..nie jestem przekonany. \n\n## Praga\nW tym samym ES jest też możliwość dotarcia do Pragi, kolejna pozycja to EN z pragi do Warszawy i powrót z Warszawy do Olsztyna[^2]\n\n\n| Pozycja           | EUR | PLN     |\n| ----------------- | --- | ------- |\n| ES                | 179 | ~767,33 |\n| EN Praga-Warszawa |     | 196,66  |\n| Warszawa-Olsztyn  |     | 16,36   |\n| Suma              |     | 980,35  |\n\n## Monachium\n\n| Pozycja                | EUR    | PLN    |\n| ---------------------- | ------ | ------ |\n| EN Amsterdam-Monachium | 105,50 | 452,25 |\n| EN Monachium-Warszawa  |        | 437,56 |\n| Warszawa-Olsztyn       |        | 16,36  |\n| Suma                   |        | 906,17 |\n\n## Drezno\n\nInspiracja z przedziaławki - podróż European Sleeperem do Drezna, stamtąd przesiadka do Zgorzelca, a stamtąd przesiadka we Wrocławiu. Szczerze? Jak spojrzałem na tą propozycję - stwierdziłem że już jestem za stary na takie zabawy. \n\n| Pozycja             | EUR   | PLN    |\n| ------------------- | ----- | ------ |\n| ES                  | 179   | 767,33 |\n| Drezno - Zgorzelec  | 34,90 | 149,61 |\n| Zgorzelec - Wrocław |       | 20,40  |\n| Wrocław-Olsztyn     |       | 49,77  |\n\n\n## Wiedeń\n\nAkurat te bilety na ten euronight zostały wyprzedane(a szkoda). W każdym razie intercity promo ma na tej trasie praskie ceny - około 200zł.\n\n\n## Połączenia mieszane\n\n## Hamburg\n\nPod rozwagę gdyby ktoś szukał inspiracji zostawiam że loty z Hamburga bywają znacznie tańsze niż z Amsterdamu - mnie odstraszyła głównie dopłata za bagaż podręczny[^3]. Jest tak blisko do Amsterdamu, że nie ma żadnych nocnych \n\n## Dortmund\n\nRozważając kiedyś wyjazd na jeden festiwal gdzie [[Ophidian]] grał, zwróciłem uwagę na to że któraś z tanich linii lotniczy miała tanie połączenie z [[Lotnisko Szymany]].  Niestety, połączenia zostały zawieszone.\n## Eindhoven\n\nStamtąd moja podróż się zaczynała, dlatego nie miałem ochoty za bardzo wracać[^4] - zresztą ceny biletów nie były jakieś szczególnie przystępne.\n# Inne rozwiązania\n\n## Flixbus z Berlina \nZa około 200zł jest 11h powrotu autokarem do Olsztyna. \n\n# Podsumowanie\n\nZdecydowałem się na powrót przez Monachium. Muzeum BMW, duże parki i bodajże fajne muzea ze sztuką brzmią jak fajny pomysł na dzień.\n\n[^1]: Umykały mi te połączenia z powodu że nie startują z Amsterdam Centraal, tylko jakiegoś innego połączenia. \n[^2]: Też jestem pod wrażeniem jakie niesamowite zniżki mi wchodzą, ale to w większości efekt kupowania porannego biletu z ogromnym wyprzedzeniem chyba.\n[^3]: Który i tak mam wrażenie że wziąłem na siłę na te kilka dni.\n[^4]: #ADHD thing, aby wciąż do przodu i wciąż doświadczań nowych bodżców.","src/content/thoughts/pl/2024/06/jak-wrocic-z-amsterdamu.md","b5e1cf285f7e04a9",{html:370,metadata:371},"<p>Podejmując skądinąd odważną decyzję o wyprawie na  Dominator 2024 i urozmaicając to wypadem do Amsterdamu, pozostaje jeszcze wątek <em>jak wrócić?</em></p>\n<h2 id=\"warunki-brzegowe\">Warunki brzegowe</h2>\n<p>Zakładam że po całym poniedziałku w Amsterdamie zaczyna się wątek powrotu - czyli do dyspozycji jest albo nocny pociąg, albo  nocleg + powrót cały dzień albo dzień przesiadkowy w innej europejskiej stolicy.</p>\n<p>Wszystkie ceny są na dzień dzisiejszy, 07.07.24, planowane trochę do przodu tj. ten poniedziałek to 22.07. Ceny uwzględniają powrót do Olsztyna, gdzie aplikowalne, tam ze żniżką 37% w polskim PKP.</p>\n<h1 id=\"pociągi-nocne\">Pociągi nocne</h1>\n<p>Z tego co widzę, żeby koszty noclegu połączyć z kosztami transportu są takie opcje:</p>\n<h2 id=\"berlin\">Berlin</h2>\n<p>Na czas tworzenia tego postu #ChatGPT  podpowiedziało mi o istnieniu <a href=\"https://www.europeansleeper.eu/\">European Sleeper</a> , czyli jakimś reboocie pociągów sypialnianych<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup>. Jedyne dostępne na dziś połączenie to komfortowe kuszetki.</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Pozycja</th><th>EUR</th></tr></thead><tbody><tr><td>Nocny z Amsterdamu do Berlina</td><td>159</td></tr></tbody></table>\n<h3 id=\"dlaczego-berlin-to-zła-opcja-na-ten-konkretny-wyjazd\">Dlaczego Berlin to zła opcja <em>na ten konkretny wyjazd</em>?</h3>\n<p>Jakkolwiek dawien dawno chodząc po Warszawie Centralnej z pewnym rozmarzeniem spoglądałem na Berlin-Warszawa-Express zastanawiając się czy kiedykolwiek nim pojadę, to 23.07 zaczyna się remont linii RE1, przez co całość  trochę  mija się z celem - z drugiej strony jest też opcja powrotu przez Szczecin, gdzie busa jest mniej, ale..nie jestem przekonany.</p>\n<h2 id=\"praga\">Praga</h2>\n<p>W tym samym ES jest też możliwość dotarcia do Pragi, kolejna pozycja to EN z pragi do Warszawy i powrót z Warszawy do Olsztyna<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">2</a></sup></p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Pozycja</th><th>EUR</th><th>PLN</th></tr></thead><tbody><tr><td>ES</td><td>179</td><td>~767,33</td></tr><tr><td>EN Praga-Warszawa</td><td></td><td>196,66</td></tr><tr><td>Warszawa-Olsztyn</td><td></td><td>16,36</td></tr><tr><td>Suma</td><td></td><td>980,35</td></tr></tbody></table>\n<h2 id=\"monachium\">Monachium</h2>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Pozycja</th><th>EUR</th><th>PLN</th></tr></thead><tbody><tr><td>EN Amsterdam-Monachium</td><td>105,50</td><td>452,25</td></tr><tr><td>EN Monachium-Warszawa</td><td></td><td>437,56</td></tr><tr><td>Warszawa-Olsztyn</td><td></td><td>16,36</td></tr><tr><td>Suma</td><td></td><td>906,17</td></tr></tbody></table>\n<h2 id=\"drezno\">Drezno</h2>\n<p>Inspiracja z przedziaławki - podróż European Sleeperem do Drezna, stamtąd przesiadka do Zgorzelca, a stamtąd przesiadka we Wrocławiu. Szczerze? Jak spojrzałem na tą propozycję - stwierdziłem że już jestem za stary na takie zabawy.</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Pozycja</th><th>EUR</th><th>PLN</th></tr></thead><tbody><tr><td>ES</td><td>179</td><td>767,33</td></tr><tr><td>Drezno - Zgorzelec</td><td>34,90</td><td>149,61</td></tr><tr><td>Zgorzelec - Wrocław</td><td></td><td>20,40</td></tr><tr><td>Wrocław-Olsztyn</td><td></td><td>49,77</td></tr></tbody></table>\n<h2 id=\"wiedeń\">Wiedeń</h2>\n<p>Akurat te bilety na ten euronight zostały wyprzedane(a szkoda). W każdym razie intercity promo ma na tej trasie praskie ceny - około 200zł.</p>\n<h2 id=\"połączenia-mieszane\">Połączenia mieszane</h2>\n<h2 id=\"hamburg\">Hamburg</h2>\n<p>Pod rozwagę gdyby ktoś szukał inspiracji zostawiam że loty z Hamburga bywają znacznie tańsze niż z Amsterdamu - mnie odstraszyła głównie dopłata za bagaż podręczny<sup><a href=\"#user-content-fn-3\" id=\"user-content-fnref-3\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">3</a></sup>. Jest tak blisko do Amsterdamu, że nie ma żadnych nocnych</p>\n<h2 id=\"dortmund\">Dortmund</h2>\n<p>Rozważając kiedyś wyjazd na jeden festiwal gdzie [[Ophidian]] grał, zwróciłem uwagę na to że któraś z tanich linii lotniczy miała tanie połączenie z [[Lotnisko Szymany]].  Niestety, połączenia zostały zawieszone.</p>\n<h2 id=\"eindhoven\">Eindhoven</h2>\n<p>Stamtąd moja podróż się zaczynała, dlatego nie miałem ochoty za bardzo wracać<sup><a href=\"#user-content-fn-4\" id=\"user-content-fnref-4\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">4</a></sup> - zresztą ceny biletów nie były jakieś szczególnie przystępne.</p>\n<h1 id=\"inne-rozwiązania\">Inne rozwiązania</h1>\n<h2 id=\"flixbus-z-berlina\">Flixbus z Berlina</h2>\n<p>Za około 200zł jest 11h powrotu autokarem do Olsztyna.</p>\n<h1 id=\"podsumowanie\">Podsumowanie</h1>\n<p>Zdecydowałem się na powrót przez Monachium. Muzeum BMW, duże parki i bodajże fajne muzea ze sztuką brzmią jak fajny pomysł na dzień.</p>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"sr-only\" id=\"footnote-label\">Footnotes</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>Umykały mi te połączenia z powodu że nie startują z Amsterdam Centraal, tylko jakiegoś innego połączenia. <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-2\">\n<p>Też jestem pod wrażeniem jakie niesamowite zniżki mi wchodzą, ale to w większości efekt kupowania porannego biletu z ogromnym wyprzedzeniem chyba. <a href=\"#user-content-fnref-2\" data-footnote-backref=\"\" aria-label=\"Back to reference 2\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-3\">\n<p>Który i tak mam wrażenie że wziąłem na siłę na te kilka dni. <a href=\"#user-content-fnref-3\" data-footnote-backref=\"\" aria-label=\"Back to reference 3\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-4\">\n<p>#ADHD thing, aby wciąż do przodu i wciąż doświadczań nowych bodżców. <a href=\"#user-content-fnref-4\" data-footnote-backref=\"\" aria-label=\"Back to reference 4\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:372,localImagePaths:419,remoteImagePaths:420,frontmatter:421,imagePaths:426},[373,376,379,382,385,388,391,394,397,400,403,406,409,412,415,418],{depth:42,slug:374,text:375},"warunki-brzegowe","Warunki brzegowe",{depth:39,slug:377,text:378},"pociągi-nocne","Pociągi nocne",{depth:42,slug:380,text:381},"berlin","Berlin",{depth:287,slug:383,text:384},"dlaczego-berlin-to-zła-opcja-na-ten-konkretny-wyjazd","Dlaczego Berlin to zła opcja na ten konkretny wyjazd?",{depth:42,slug:386,text:387},"praga","Praga",{depth:42,slug:389,text:390},"monachium","Monachium",{depth:42,slug:392,text:393},"drezno","Drezno",{depth:42,slug:395,text:396},"wiedeń","Wiedeń",{depth:42,slug:398,text:399},"połączenia-mieszane","Połączenia mieszane",{depth:42,slug:401,text:402},"hamburg","Hamburg",{depth:42,slug:404,text:405},"dortmund","Dortmund",{depth:42,slug:407,text:408},"eindhoven","Eindhoven",{depth:39,slug:410,text:411},"inne-rozwiązania","Inne rozwiązania",{depth:42,slug:413,text:414},"flixbus-z-berlina","Flixbus z Berlina",{depth:39,slug:416,text:417},"podsumowanie","Podsumowanie",{depth:42,slug:43,text:44},[],[],{title:362,draft:19,tags:422,aliases:423,date:424,previewHtml:425},[17,18,158,365],[362],["Date","2024-07-07T00:00:00.000Z"],"<p>Podejmując skądinąd odważną decyzję o wyprawie na  Dominator 2024 i urozmaicając to wypadem do Amsterdamu, pozostaje jeszcze wątek <em>jak wrócić?</em></p><h2>Warunki brzegowe</h2><p>Zakładam że po całym poniedziałku w Amsterdamie zaczyna się wątek powrotu - czyli do dyspozycji jest albo nocny pociąg, albo  nocleg + powrót cały dzień albo dzień przesiadkowy w innej europejskiej stolicy.</p><p>Wszystkie ceny są na dzień dzisiejszy, 07.07.24, planowane trochę do przodu tj. ten poniedziałek to 22.07. Ceny uwzględniają powrót do Olsztyna, gdzie aplikowalne, tam ze żniżką 37% w polskim PKP.</p><h1>Pociągi nocne</h1><p>Z tego co widzę, żeby koszty noclegu połączyć z kosztami transportu są takie opcje:</p><h2>Berlin</h2><p>Na czas tworzenia tego postu #ChatGPT  podpowiedziało mi o istnieniu <a href=\"https://www.europeansleeper.eu/\">European Sleeper</a> , czyli jakimś reboocie pociągów sypialnianych<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup>. Jedyne dostępne na dziś połączenie to komfortowe kuszetki.</p><table>\n<thead>\n<tr>\n<th>Pozycja</th>\n<th>EUR</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>Nocny z Amsterdamu do Berlina</td>\n<td>159</td>\n</tr>\n</tbody>\n</table><h3>Dlaczego Berlin to zła opcja <em>na ten konkretny wyjazd</em>?</h3><p>Jakkolwiek dawien dawno chodząc po Warszawie Centralnej z pewnym rozmarzeniem spoglądałem na Berlin-Warszawa-Express zastanawiając się czy kiedykolwiek nim pojadę, to 23.07 zaczyna się remont linii RE1, przez co całość  trochę  mija się z celem - z drugiej strony jest też opcja powrotu przez Szczecin, gdzie busa jest mniej, ale..nie jestem przekonany.</p><h2>Praga</h2><p>W tym samym ES jest też możliwość dotarcia do Pragi, kolejna pozycja to EN z pragi do Warszawy i powrót z Warszawy do Olsztyna<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup></p><table>\n<thead>\n<tr>\n<th>Pozycja</th>\n<th>EUR</th>\n<th>PLN</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>ES</td>\n<td>179</td>\n<td>~767,33</td>\n</tr>\n<tr>\n<td>EN Praga-Warszawa</td>\n<td></td>\n<td>196,66</td>\n</tr>\n<tr>\n<td>Warszawa-Olsztyn</td>\n<td></td>\n<td>16,36</td>\n</tr>\n<tr>\n<td>Suma</td>\n<td></td>\n<td>980,35</td>\n</tr>\n</tbody>\n</table><h2>Monachium</h2><table>\n<thead>\n<tr>\n<th>Pozycja</th>\n<th>EUR</th>\n<th>PLN</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>EN Amsterdam-Monachium</td>\n<td>105,50</td>\n<td>452,25</td>\n</tr>\n<tr>\n<td>EN Monachium-Warszawa</td>\n<td></td>\n<td>437,56</td>\n</tr>\n<tr>\n<td>Warszawa-Olsztyn</td>\n<td></td>\n<td>16,36</td>\n</tr>\n<tr>\n<td>Suma</td>\n<td></td>\n<td>906,17</td>\n</tr>\n</tbody>\n</table><h2>Drezno</h2><p>Inspiracja z przedziaławki - podróż European Sleeperem do Drezna, stamtąd przesiadka do Zgorzelca, a stamtąd przesiadka we Wrocławiu. Szczerze? Jak spojrzałem na tą propozycję - stwierdziłem że już jestem za stary na takie zabawy.</p><table>\n<thead>\n<tr>\n<th>Pozycja</th>\n<th>EUR</th>\n<th>PLN</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td>ES</td>\n<td>179</td>\n<td>767,33</td>\n</tr>\n<tr>\n<td>Drezno - Zgorzelec</td>\n<td>34,90</td>\n<td>149,61</td>\n</tr>\n<tr>\n<td>Zgorzelec - Wrocław</td>\n<td></td>\n<td>20,40</td>\n</tr>\n<tr>\n<td>Wrocław-Olsztyn</td>\n<td></td>\n<td>49,77</td>\n</tr>\n</tbody>\n</table><h2>Wiedeń</h2><p>Akurat te bilety na ten euronight zostały wyprzedane(a szkoda). W każdym razie intercity promo ma na tej trasie praskie ceny - około 200zł.</p><h2>Połączenia mieszane</h2><h2>Hamburg</h2><p>Pod rozwagę gdyby ktoś szukał inspiracji zostawiam że loty z Hamburga bywają znacznie tańsze niż z Amsterdamu - mnie odstraszyła głównie dopłata za bagaż podręczny<sup><a href=\"#user-content-fn-3\" id=\"user-content-fnref-3\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup>. Jest tak blisko do Amsterdamu, że nie ma żadnych nocnych</p><h2>Dortmund</h2><p>Rozważając kiedyś wyjazd na jeden festiwal gdzie [[Ophidian]] grał, zwróciłem uwagę na to że któraś z tanich linii lotniczy miała tanie połączenie z [[Lotnisko Szymany]].  Niestety, połączenia zostały zawieszone.</p><h2>Eindhoven</h2><p>Stamtąd moja podróż się zaczynała, dlatego nie miałem ochoty za bardzo wracać<sup><a href=\"#user-content-fn-4\" id=\"user-content-fnref-4\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup> - zresztą ceny biletów nie były jakieś szczególnie przystępne.</p><h1>Inne rozwiązania</h1><h2>Flixbus z Berlina</h2><p>Za około 200zł jest 11h powrotu autokarem do Olsztyna.</p><h1>Podsumowanie</h1><p>Zdecydowałem się na powrót przez Monachium. Muzeum BMW, duże parki i bodajże fajne muzea ze sztuką brzmią jak fajny pomysł na dzień.</p>",[],"pl/2024/06/udar-a-alkohol",{id:427,data:429,body:435,filePath:436,digest:437,rendered:438},{title:430,date:431,tags:432,draft:19},"Udar a alkohol",["Date","2024-06-13T00:00:00.000Z"],[433,105,434],"Alkohol","Praca magisterska","_Żeby mieć trochę contentu, wrzucam stare podejścia do pisania_\n\n Przechodząc przez literaturę do pracy magisterskiej znalazłem jedną, nieoczywistą ciekawostkę: otóż małe[^1] spożycie alkoholu zmniejsza prawdopodobieństwo udaru krwotocznego. Na krwotoczny nie robi różnicy - natomiast picie dużo bądź w ciągach już te prawdopodobieństwo dość mocno zwiększa.\n \n> Light and moderate alcohol consumption was associated with a lower risk of ischemic stroke, whereas high and heavy drinking was associated with an increased risk;\n\n[Źródło.](https://bmcmedicine.biomedcentral.com/articles/10.1186/s12916-016-0721-4) \n\nOczywiście, to nie wyraża mojej opinii wobec alkoholu - tutaj bliżej mi do perspektywy Davida Nutta, autora m.in. [[Narkotyki bez paniki]] która określa alkohol mianem najbardziej szkodliwej używki[^2] - w analizie która nie patrzy tylko na koszty osobowo/zdrowotne, ale patrzy szerzej, uwzględniając też koszty społeczne danej związane z daną substancją.\n\n[^1]: Do 12 gram alkoholu etylowego.\n[^2]: Niestety premiera nowej książki wyparła z SEO googla stare artykuły na ten temat","src/content/thoughts/pl/2024/06/udar-a-alkohol.md","75279fddef7aee26",{html:439,metadata:440},"<p><em>Żeby mieć trochę contentu, wrzucam stare podejścia do pisania</em></p>\n<p>Przechodząc przez literaturę do pracy magisterskiej znalazłem jedną, nieoczywistą ciekawostkę: otóż małe<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup> spożycie alkoholu zmniejsza prawdopodobieństwo udaru krwotocznego. Na krwotoczny nie robi różnicy - natomiast picie dużo bądź w ciągach już te prawdopodobieństwo dość mocno zwiększa.</p>\n<blockquote>\n<p>Light and moderate alcohol consumption was associated with a lower risk of ischemic stroke, whereas high and heavy drinking was associated with an increased risk;</p>\n</blockquote>\n<p><a href=\"https://bmcmedicine.biomedcentral.com/articles/10.1186/s12916-016-0721-4\">Źródło.</a></p>\n<p>Oczywiście, to nie wyraża mojej opinii wobec alkoholu - tutaj bliżej mi do perspektywy Davida Nutta, autora m.in. [[Narkotyki bez paniki]] która określa alkohol mianem najbardziej szkodliwej używki<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">2</a></sup> - w analizie która nie patrzy tylko na koszty osobowo/zdrowotne, ale patrzy szerzej, uwzględniając też koszty społeczne danej związane z daną substancją.</p>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"sr-only\" id=\"footnote-label\">Footnotes</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>Do 12 gram alkoholu etylowego. <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n<li id=\"user-content-fn-2\">\n<p>Niestety premiera nowej książki wyparła z SEO googla stare artykuły na ten temat <a href=\"#user-content-fnref-2\" data-footnote-backref=\"\" aria-label=\"Back to reference 2\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:441,localImagePaths:443,remoteImagePaths:444,frontmatter:445,imagePaths:449},[442],{depth:42,slug:43,text:44},[],[],{title:430,draft:19,tags:446,date:447,previewHtml:448},[433,105,434],["Date","2024-06-13T00:00:00.000Z"],"<p><em>Żeby mieć trochę contentu, wrzucam stare podejścia do pisania</em></p><p>Przechodząc przez literaturę do pracy magisterskiej znalazłem jedną, nieoczywistą ciekawostkę: otóż małe<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup> spożycie alkoholu zmniejsza prawdopodobieństwo udaru krwotocznego. Na krwotoczny nie robi różnicy - natomiast picie dużo bądź w ciągach już te prawdopodobieństwo dość mocno zwiększa.</p><blockquote>\n<p>Light and moderate alcohol consumption was associated with a lower risk of ischemic stroke, whereas high and heavy drinking was associated with an increased risk;</p>\n</blockquote><p><a href=\"https://bmcmedicine.biomedcentral.com/articles/10.1186/s12916-016-0721-4\">Źródło.</a></p><p>Oczywiście, to nie wyraża mojej opinii wobec alkoholu - tutaj bliżej mi do perspektywy Davida Nutta, autora m.in. [[Narkotyki bez paniki]] która określa alkohol mianem najbardziej szkodliwej używki<sup><a href=\"#user-content-fn-2\" id=\"user-content-fnref-2\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup> - w analizie która nie patrzy tylko na koszty osobowo/zdrowotne, ale patrzy szerzej, uwzględniając też koszty społeczne danej związane z daną substancją.</p>",[],"pl/2024/06/malarstwo-a-design-thinking",{id:450,data:452,body:460,filePath:461,digest:462,rendered:463},{title:453,date:454,tags:455,draft:19},"Co wspólnego ma malarstwo z design thinking",["Date","2024-07-27T00:00:00.000Z"],[456,457,458,459],"Design Thinking","Malarstwo","Sztuka","Wywiady","Jestem jeszcze w czasie gdy dość łapczywie przeglądam zdjęcia z podróży i teraz stwierdziłem że w ramach nasilenia prokrastynacji chcę zobaczyć o co chodzi z książką [*Lie like an artist*](https://www.bispublishers.com/lie-like-an-artist.html) - widziałem ją w przymuzealnych sklepikach zarazem w trzech miastach gdzie miałem okazję zajrzeć do miejsc związanych ze sztuką.\n\nAle przypadkiem trafiłem na artykuł o tym [samym tytule](https://www.roxinekee.com/blog/lie-like-an-artist)\nz którego jeden cytat przykuł moją szczególną uwagę:\n\n> According to our tour guide, McArdle did painstaking truth-finding to produce these two paintings. He conducted countless interviews with veterans, pored through maps and sketches, probably went to these places himself.\n\nMam dość luźne skojarzenie z tym jak Design thinking wygląda obecnie, gdzie wywiady pełnią tę istotną rolę czerpania informacji i tworzenia jeszcze lepszego doświadczenia użytkownika.","src/content/thoughts/pl/2024/06/malarstwo-a-design-thinking.md","ae9a7e87178ce96e",{html:464,metadata:465},"<p>Jestem jeszcze w czasie gdy dość łapczywie przeglądam zdjęcia z podróży i teraz stwierdziłem że w ramach nasilenia prokrastynacji chcę zobaczyć o co chodzi z książką <a href=\"https://www.bispublishers.com/lie-like-an-artist.html\"><em>Lie like an artist</em></a> - widziałem ją w przymuzealnych sklepikach zarazem w trzech miastach gdzie miałem okazję zajrzeć do miejsc związanych ze sztuką.</p>\n<p>Ale przypadkiem trafiłem na artykuł o tym <a href=\"https://www.roxinekee.com/blog/lie-like-an-artist\">samym tytule</a>\nz którego jeden cytat przykuł moją szczególną uwagę:</p>\n<blockquote>\n<p>According to our tour guide, McArdle did painstaking truth-finding to produce these two paintings. He conducted countless interviews with veterans, pored through maps and sketches, probably went to these places himself.</p>\n</blockquote>\n<p>Mam dość luźne skojarzenie z tym jak Design thinking wygląda obecnie, gdzie wywiady pełnią tę istotną rolę czerpania informacji i tworzenia jeszcze lepszego doświadczenia użytkownika.</p>",{headings:466,localImagePaths:467,remoteImagePaths:468,frontmatter:469,imagePaths:473},[],[],[],{title:453,draft:19,tags:470,date:471,previewHtml:472},[456,457,458,459],["Date","2024-07-27T00:00:00.000Z"],"<p>Jestem jeszcze w czasie gdy dość łapczywie przeglądam zdjęcia z podróży i teraz stwierdziłem że w ramach nasilenia prokrastynacji chcę zobaczyć o co chodzi z książką <a href=\"https://www.bispublishers.com/lie-like-an-artist.html\"><em>Lie like an artist</em></a> - widziałem ją w przymuzealnych sklepikach zarazem w trzech miastach gdzie miałem okazję zajrzeć do miejsc związanych ze sztuką.</p><p>Ale przypadkiem trafiłem na artykuł o tym <a href=\"https://www.roxinekee.com/blog/lie-like-an-artist\">samym tytule</a>\nz którego jeden cytat przykuł moją szczególną uwagę:</p><blockquote>\n<p>According to our tour guide, McArdle did painstaking truth-finding to produce these two paintings. He conducted countless interviews with veterans, pored through maps and sketches, probably went to these places himself.</p>\n</blockquote><p>Mam dość luźne skojarzenie z tym jak Design thinking wygląda obecnie, gdzie wywiady pełnią tę istotną rolę czerpania informacji i tworzenia jeszcze lepszego doświadczenia użytkownika.</p>",[],"pl/2024/06/dpd-a-przesylki",{id:474,data:476,body:483,filePath:484,digest:485,rendered:486},{title:477,date:478,tags:479,draft:19},"DPD a przesyłki - jak poprawić jakość niskim kosztem?",["Date","2024-06-13T00:00:00.000Z"],[480,159,481,482],"Typ/insight","Kurierzy","DPD","Nie, żebym samemu miał bardzo nieprzyjemne doświadczenie ze składaniem reklamacji w DPD, dlatego ten protip przeklejam z przyjemnością:\n \n>Ten magiczny \"podpis\", widoczny jako odbiorca w statusie to przepisanie nazwiska z listu na zebrze przy zatwierdzaniu. Fizycznych podpisów kurierzy nie zbierają od czasów covida. Jeśli mirek chciał do rąk odbiorcy, mógł dopłacić DPD za usługę DRW[^1] z pinem, wtedy kurier nie wrzuci takiej paczki za płot, bo będzie musiał wpisać pin od odbiorcy, żeby dobić ją w systemie. Ot cała magia.\n\n[Źródło.](https://wykop.pl/link/7465835/dpd-przerzuca-komputer-przez-plot-niszczy-go-i-bezczelnie-odrzuca-reklamacje/komentarz/124712141/na-dodatek-w-systemie-paczka-widnieje-jako-odebrana-i-podpisana-od-paru-lat-kurierzy-nie-wymagaja-podpisow-po-prostu-paczka-laduje-gdziekolwiek-pod-ty#124712705)\n\n[^1]: Do Rąk Własnych","src/content/thoughts/pl/2024/06/dpd-a-przesylki.md","12eb9ff75ecf8749",{html:487,metadata:488},"<p>Nie, żebym samemu miał bardzo nieprzyjemne doświadczenie ze składaniem reklamacji w DPD, dlatego ten protip przeklejam z przyjemnością:</p>\n<blockquote>\n<p>Ten magiczny “podpis”, widoczny jako odbiorca w statusie to przepisanie nazwiska z listu na zebrze przy zatwierdzaniu. Fizycznych podpisów kurierzy nie zbierają od czasów covida. Jeśli mirek chciał do rąk odbiorcy, mógł dopłacić DPD za usługę DRW<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref=\"\" aria-describedby=\"footnote-label\">1</a></sup> z pinem, wtedy kurier nie wrzuci takiej paczki za płot, bo będzie musiał wpisać pin od odbiorcy, żeby dobić ją w systemie. Ot cała magia.</p>\n</blockquote>\n<p><a href=\"https://wykop.pl/link/7465835/dpd-przerzuca-komputer-przez-plot-niszczy-go-i-bezczelnie-odrzuca-reklamacje/komentarz/124712141/na-dodatek-w-systemie-paczka-widnieje-jako-odebrana-i-podpisana-od-paru-lat-kurierzy-nie-wymagaja-podpisow-po-prostu-paczka-laduje-gdziekolwiek-pod-ty#124712705\">Źródło.</a></p>\n<section data-footnotes=\"\" class=\"footnotes\"><h2 class=\"sr-only\" id=\"footnote-label\">Footnotes</h2>\n<ol>\n<li id=\"user-content-fn-1\">\n<p>Do Rąk Własnych <a href=\"#user-content-fnref-1\" data-footnote-backref=\"\" aria-label=\"Back to reference 1\" class=\"data-footnote-backref\">↩</a></p>\n</li>\n</ol>\n</section>",{headings:489,localImagePaths:491,remoteImagePaths:492,frontmatter:493,imagePaths:500},[490],{depth:42,slug:43,text:44},[],[],{title:477,draft:19,tags:494,aliases:495,date:497,description:498,previewHtml:499},[480,159,481,482],[496],"DPD a przesyłki",["Date","2024-06-13T00:00:00.000Z"],"Jak prostym trikiem sprawić że paczka jednak zobaczy odbiorcę?","<p>Nie, żebym samemu miał bardzo nieprzyjemne doświadczenie ze składaniem reklamacji w DPD, dlatego ten protip przeklejam z przyjemnością:</p><blockquote>\n<p>Ten magiczny “podpis”, widoczny jako odbiorca w statusie to przepisanie nazwiska z listu na zebrze przy zatwierdzaniu. Fizycznych podpisów kurierzy nie zbierają od czasów covida. Jeśli mirek chciał do rąk odbiorcy, mógł dopłacić DPD za usługę DRW<sup><a href=\"#user-content-fn-1\" id=\"user-content-fnref-1\" data-footnote-ref aria-describedby=\"footnote-label\">1</a></sup> z pinem, wtedy kurier nie wrzuci takiej paczki za płot, bo będzie musiał wpisać pin od odbiorcy, żeby dobić ją w systemie. Ot cała magia.</p>\n</blockquote><p><a href=\"https://wykop.pl/link/7465835/dpd-przerzuca-komputer-przez-plot-niszczy-go-i-bezczelnie-odrzuca-reklamacje/komentarz/124712141/na-dodatek-w-systemie-paczka-widnieje-jako-odebrana-i-podpisana-od-paru-lat-kurierzy-nie-wymagaja-podpisow-po-prostu-paczka-laduje-gdziekolwiek-pod-ty#124712705\">Źródło.</a></p>",[]];

